```php
<?php
$numbers = [1, 2, 3, 4];

// Traditional anonymous function
$squared1 = array_map(function($n) {
    return $n * $n;
}, $numbers);

// Arrow function
$squared2 = array_map(fn($n) => $n * $n, $numbers);

print_r($squared1);
print_r($squared2); // same result
?>
```

